import zlib
import base64
import json
import random
import math
import eval7
from pkbot.actions import ActionFold, ActionCall, ActionCheck, ActionRaise, ActionBid
from pkbot.states import GameInfo, PokerState
from pkbot.base import BaseBot
from pkbot.runner import parse_args, run_bot

# =============================================================================
# 1. THE MASTER DATA 
# =============================================================================
# Paste your compressed master string here
COMPRESSED_MASTER_DATA = "" 

class Player(BaseBot):
    '''
    IIT-Pokerbots 2026: Asymmetric Information Bot
    Features: Perfect Memory CFR, Hard Raise Limits, L2 Norm Scaling, Vickrey Auctions.
    '''
    
    def __init__(self) -> None:
        self.hole_cards_eval7 = []
        self.history_str = ""
        self.current_street = "pre-flop"
        self.raises_this_street = 0
        
        self.loser_cfr_table, self.flop_centroids, self.turn_centroids = self._decompress_master_data(COMPRESSED_MASTER_DATA)

    def _decompress_master_data(self, b64_string):
        if b64_string == "eJztwTEBAAAAwqD1T+1hBqAAAAAAAAAAAAAAAAAAAA==":
            return {}, {}, {} 
            
        json_str = zlib.decompress(base64.b64decode(b64_string)).decode('utf-8')
        master_data = json.loads(json_str)
        cfr_table = {k: [p / 100.0 for p in v] for k, v in master_data.get("cfr_table", {}).items()}
        return cfr_table, master_data.get("flop_centroids", {}), master_data.get("turn_centroids", {})

    def on_hand_start(self, game_info: GameInfo, current_state: PokerState) -> None:
        self.hole_cards_eval7 = [eval7.Card(c) for c in current_state.my_hand]
        # Reset state trackers for the new hand
        self.history_str = ""
        self.current_street = "pre-flop"
        self.raises_this_street = 0

    def on_hand_end(self, game_info: GameInfo, current_state: PokerState) -> None: 
        pass

    def get_move(self, game_info: GameInfo, current_state: PokerState):
        street = current_state.street
        if street == 'pre-flop' or street == 'pre-flop': return self._handle_preflop(current_state)
        elif street == 'auction': return self._handle_auction(current_state)
        
        if len(current_state.opp_revealed_cards) > 0:
            return self._handle_winner_state(current_state)
        else:
            return self._handle_loser_state(current_state) 

    # =========================================================================
    # CORE STRATEGIES
    # =========================================================================
    def _handle_preflop(self, current_state: PokerState):
        if current_state.can_act(ActionRaise):
            return ActionRaise(current_state.raise_bounds[0])
        return ActionCall() if current_state.can_act(ActionCall) else ActionCheck()

    def _handle_auction(self, current_state: PokerState) -> ActionBid:
        pot = sum(current_state.pot) if isinstance(current_state.pot, list) else current_state.pot
        board_eval7 = [eval7.Card(c) for c in current_state.board]
        equity = self._fast_equity(self.hole_cards_eval7, board_eval7, iterations=500)
        
        if equity > 0.85 or equity < 0.20: return ActionBid(0)
        return ActionBid(int(pot * 0.15))

    def _handle_winner_state(self, current_state: PokerState):
        opp_card_str = current_state.opp_revealed_cards[0]
        board_eval7 = [eval7.Card(c) for c in current_state.board]
        collapsed_range = self._get_collapsed_range(opp_card_str, current_state)
        equity_vs_range = self._eval7_equity_vs_range(self.hole_cards_eval7, collapsed_range, board_eval7)
        
        if equity_vs_range > 0.60 and current_state.can_act(ActionRaise):
            return ActionRaise(current_state.raise_bounds[0])
        elif equity_vs_range < 0.30 and current_state.can_act(ActionFold):
            return ActionFold()
        return ActionCheck() if current_state.can_act(ActionCheck) else ActionCall()

    def _handle_loser_state(self, current_state: PokerState):
        """TRACK B: Perfect Memory tracking with Hard Raise Limits and Pruned Fallbacks."""
        street = current_state.street
        
        if street in ['flop', 'turn']:
            # 1. Handle Street Transitions
            if street != self.current_street:
                if self.current_street == 'flop':
                    self.history_str += "t"
                self.current_street = street
                self.raises_this_street = 0
                
            board_eval7 = [eval7.Card(c) for c in current_state.board]
            live_eq = self._fast_equity(self.hole_cards_eval7, board_eval7, 500) * 1000.0
            live_wet = self._calculate_board_wetness(board_eval7) * 1000.0
            bucket_id = self._get_closest_centroid([live_eq, live_wet], street)
            
            # 2. Read Opponent's Action
            facing_bet = not current_state.can_act(ActionCheck)
            current_st_hist = self.history_str.split('t')[-1]
            
            if facing_bet:
                if not current_st_hist.endswith('2') and not current_st_hist.endswith('3'):
                    self.history_str += "2"
            else:
                if current_st_hist == "":
                    self.history_str += "1"
                    
            # 3. EXACT CFR Lookup
            abstract_state = f"{street[0]}{bucket_id}_{self.history_str}"
            raw_strategy = self.loser_cfr_table.get(abstract_state, None)
            
            if raw_strategy is None:
                strategy = [0.25, 0.25, 0.25, 0.25]
                print(f"[CFR MISS] '{abstract_state}'. Defaulting to {strategy}")
            else:
                strategy = list(raw_strategy) # Cast to list to avoid mutating dictionary
                print(f"[CFR HIT] Found '{abstract_state}' -> {strategy}")
            
            # 4. THE HARD LIMIT ENFORCER
            if self.raises_this_street >= 2:
                strategy[2] = 0.0
                strategy[3] = 0.0
                norm_sum = strategy[0] + strategy[1]
                if norm_sum > 0:
                    strategy = [strategy[0] / norm_sum, strategy[1] / norm_sum, 0.0, 0.0]
                else:
                    strategy = [0.5, 0.5, 0.0, 0.0] 
                    
            # 5. Execute & Record our Action
            action, act_char = self._sample_action(strategy, current_state)
            self.history_str += act_char
            if act_char in ['2', '3']:
                self.raises_this_street += 1
                
            return action
            
        elif street == 'river':
            return self._river_mdf_logic(current_state)

    def _river_mdf_logic(self, current_state: PokerState):
        board_eval7 = [eval7.Card(c) for c in current_state.board]
        equity = self._fast_equity(self.hole_cards_eval7, board_eval7, iterations=400)
        
        if not current_state.can_act(ActionCheck):
            if equity > 0.60: return ActionCall()
            return ActionFold() if current_state.can_act(ActionFold) else ActionCheck()
        else:
            if equity > 0.85 and current_state.can_act(ActionRaise):
                pot = sum(current_state.pot) if isinstance(current_state.pot, list) else current_state.pot
                min_r, max_r = current_state.raise_bounds
                target = max(min_r, min(int(pot * 0.5), max_r))
                return ActionRaise(target)
            return ActionCheck()

    # =========================================================================
    # FAST MATH & UTILITIES
    # =========================================================================
    def _sample_action(self, strategy: list, current_state: PokerState):
        """Converts probabilities into engine actions AND character codes for perfect memory."""
        actions = ["fold", "call", "raise_50", "raise_200"]
        chosen = random.choices(actions, weights=strategy, k=1)[0]
        
        if chosen == "fold" and current_state.can_act(ActionFold):
            return ActionFold(), "0"
            
        if "raise" in chosen and current_state.can_act(ActionRaise):
            min_raise, max_raise = current_state.raise_bounds
            pot = sum(current_state.pot) if isinstance(current_state.pot, list) else current_state.pot
            
            target = 0
            act_char = "2"
            
            if chosen == "raise_50": 
                target = int(pot * 0.5)
                act_char = "2"
            elif chosen == "raise_200": 
                target = int(pot * 2.0)
                act_char = "3"
            
            target = max(min_raise, min(target, max_raise))
            return ActionRaise(target), act_char
            
        if current_state.can_act(ActionCall):
            return ActionCall(), "1"
        else:
            return ActionCheck(), "1"

    def _get_closest_centroid(self, live_features: list, street: str) -> str:
        centroids = self.flop_centroids if street == 'flop' else self.turn_centroids
        if not centroids: return "0"
        
        best_bucket = "0"
        min_distance = float('inf')
        
        for bucket_key, centroid_features in centroids.items():
            dist = math.sqrt((live_features[0] - centroid_features[0])**2 + (live_features[1] - centroid_features[1])**2)
            if dist < min_distance:
                min_distance = dist
                best_bucket = bucket_key.split('_')[1] 
                
        return best_bucket

    def _fast_equity(self, my_cards_eval7, board_eval7, iterations=500):
        deck = eval7.Deck()
        for c in my_cards_eval7 + board_eval7: deck.cards.remove(c)
        wins = 0
        for _ in range(iterations):
            deck.shuffle()
            opp_cards = deck.peek(2)
            rem_board = deck.peek(5)[2: 5 - len(board_eval7)]
            if eval7.evaluate(my_cards_eval7 + board_eval7 + rem_board) > eval7.evaluate(opp_cards + board_eval7 + rem_board): wins += 1
        return wins / iterations

    def _get_collapsed_range(self, revealed_card_str: str, current_state: PokerState) -> list:
        deck = eval7.Deck()
        revealed_eval7 = eval7.Card(revealed_card_str)
        deck.cards.remove(revealed_eval7)
        for c in current_state.board + current_state.my_hand:
            if eval7.Card(c) in deck.cards: deck.cards.remove(eval7.Card(c))
        return [[revealed_eval7, card] for card in deck.cards]

    def _eval7_equity_vs_range(self, my_cards_eval7, opp_range_eval7, board_eval7):
        wins = sum(1 for opp_hand in opp_range_eval7 if eval7.evaluate(my_cards_eval7 + board_eval7) >= eval7.evaluate(opp_hand + board_eval7))
        return wins / len(opp_range_eval7) if opp_range_eval7 else 0

    def _calculate_board_wetness(self, board_eval7):
        if len(board_eval7) < 3: return 0.0
        suits = [c.suit for c in board_eval7]
        ranks = sorted([c.rank for c in board_eval7])
        flush_wetness = (max(suits.count(s) for s in set(suits)) - 1) / 4.0 
        straight_wetness = max(0, 1.0 - (sum(ranks[i+1] - ranks[i] for i in range(len(ranks)-1)) / 12.0))
        return min(1.0, flush_wetness + straight_wetness)

if __name__ == '__main__':
    run_bot(Player(), parse_args())